class Solution:
    def checkPrimeFrequency(self, nums):
        from collections import Counter
        def is_prime(x):
            if x < 2:
                return False
            i = 2
            while i * i <= x:
                if x % i == 0:
                    return False
                i += 1
            return True
        return any(is_prime(c) for c in Counter(nums).values())

