var checkPrimeFrequency = function(nums) {
    const freq = new Map();
    for (const x of nums) freq.set(x, (freq.get(x) || 0) + 1);
    const isPrime = (x) => {
        if (x < 2) return false;
        for (let i = 2; i * i <= x; i++) if (x % i === 0) return false;
        return true;
    };
    for (const c of freq.values()) if (isPrime(c)) return true;
    return false;
};
